using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
/// Prompt templates for content summarization.
/// </summary>
[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specific focus or angle.")]
    public static ChatMessage SummarizeWithFocus(
        [Description("The content to summarize")] string content,
        [Description("The topic or angle to focus on")] string focus) =>
        new(ChatRole.User,
            $"Summarize the following content, focusing specifically on \"{focus}\":\n\n{content}");
}

